import Style from "./auth.module.css";
import { useState } from "react";
import { useNavigate } from 'react-router-dom';

export default function Signup(){

    const navs = useNavigate();

    const [ username, setUsername ] = useState("");
    const [ password, setPassword ] = useState(""); 
    const [ email, setEmail ]  = useState("");

    const check = () => {
        console.log(`username: ${username}, password: ${password}, email: ${email}`);
    }
    
    return(
        <div className={Style.box}>
            <div>
                <div >
                    <h1>Sign up</h1>
                </div>
            </div>
            <div className={Style.inputs}>
                <div className={Style.inputbox}>
                    <label htmlFor="username">username:</label>
                    <input type="text" id="username" onChange={(value) => {setUsername(value.target.value)}}></input>
                </div>
                <div className={Style.inputbox}>
                    <label htmlFor="password">Password:</label>
                    <input type="password" id="password" onChange={(value) => {setPassword(value.target.value)}}></input>
                </div>
                    <div className={Style.inputbox}>
                    <label htmlFor="email">email:</label>
                    <input type="password" id="email" onChange={(value) => {setEmail(value.target.value)}}></input>
                </div>
            </div>
            <div className={Style.button}>
                <div>
                    <button onClick={() => {check()}}>sign up</button>
                </div>
                <div>
                    <button onClick={() => {navs("/auth/signin")}}>sign in</button>
                </div>
            </div>
        </div>
    )
}
